use distributed_inference::gnosis_foil::{
    foil_async_loser_queue_telemetry, foil_core_boost_retention_floor,
    foil_wait_for_async_loser_queue_drain, rf_fibonacci_race_resident_cache_sample,
    RaceLoserPolicy, RfFibonacciSmartSkipCache, RfFibonacciWinnerCacheStatus,
};
use distributed_inference::rf_physics_cpu::{
    RfPhysicsCpuObservation, RfSignalGate, MONSTER_VECTOR_FLOOR,
};
use serde::Serialize;
use std::time::{Duration, Instant};

#[derive(Serialize)]
struct PolicyBenchRow {
    policy: &'static str,
    iterations: u32,
    target_n: u32,
    workload: &'static str,
    elapsed_ns: u128,
    mean_ns: f64,
    p50_ns: u128,
    p95_ns: u128,
    p99_ns: u128,
    verified: bool,
    winner: &'static str,
    cache_hits: u32,
    cache_misses: u32,
    cache_fresh: u32,
    cache_absent_built: u32,
    cache_stale_rebuilt: u32,
    retained_witness_hits: usize,
    recomputable_skips: usize,
    loser_kernels_drained: usize,
    loser_kernels_dropped: usize,
    queue_admitted_tasks: u64,
    queue_dropped_tasks: u64,
    queue_completed_tasks: u64,
    queue_pending_before: u64,
    queue_pending_after: u64,
    queue_drained_before: bool,
    queue_worker_count: usize,
}

fn main() {
    let iterations = arg_u32("--iterations").unwrap_or(200);
    if iterations == 0 {
        fail_with_usage("--iterations must be greater than 0");
    }
    let target_n = arg_u32("--n").unwrap_or(20);
    let repetitions = arg_u32("--repetitions").unwrap_or(2);
    let workload = arg_string("--workload").unwrap_or_else(|| "fixed".to_owned());
    let workload_name = normalized_workload(&workload)
        .unwrap_or_else(|| fail_with_usage(&format!("unknown --workload '{workload}'")));
    let drain_queue_between_policies = arg_bool("--drain-queue-between-policies");
    let drain_timeout = Duration::from_millis(arg_u64("--drain-timeout-ms").unwrap_or(1000));
    let policy_arg = arg_string("--policy");
    let policies = selected_policies(policy_arg.as_deref())
        .unwrap_or_else(|unknown| fail_with_usage(&format!("unknown --policy '{unknown}'")));
    let observation = RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
        potential_channels: MONSTER_VECTOR_FLOOR,
        witness_signal: 20,
        activation_threshold: 20,
    });

    let rows = policies
        .into_iter()
        .map(|policy| {
            let drained_before = if drain_queue_between_policies {
                foil_wait_for_async_loser_queue_drain(drain_timeout)
            } else {
                foil_async_loser_queue_telemetry()
            };
            let queue_before = drained_before;
            let started = Instant::now();
            let mut cache: Option<RfFibonacciSmartSkipCache> = None;
            let mut verified = true;
            let mut winner = "none";
            let mut cache_hits = 0;
            let mut cache_misses = 0;
            let mut cache_fresh = 0;
            let mut cache_absent_built = 0;
            let mut cache_stale_rebuilt = 0;
            let mut retained_witness_hits = 0;
            let mut recomputable_skips = 0;
            let mut loser_kernels_drained = 0;
            let mut loser_kernels_dropped = 0;
            let mut sample_ns = Vec::with_capacity(iterations as usize);
            for iteration in 0..iterations {
                let next_n = workload_n(workload_name, iteration, target_n);
                let sample_started = Instant::now();
                let report = rf_fibonacci_race_resident_cache_sample(
                    next_n,
                    &observation,
                    repetitions,
                    &mut cache,
                    foil_core_boost_retention_floor(),
                    policy,
                )
                .expect("FOIL race benchmark should complete");
                sample_ns.push(sample_started.elapsed().as_nanos());
                verified &= report.verified;
                winner = report.winner;
                cache_hits += report.cache_hit_count;
                cache_misses += report.cache_miss_count;
                match report.cache_status {
                    RfFibonacciWinnerCacheStatus::Fresh => cache_fresh += 1,
                    RfFibonacciWinnerCacheStatus::AbsentBuilt => cache_absent_built += 1,
                    RfFibonacciWinnerCacheStatus::StaleRebuilt => cache_stale_rebuilt += 1,
                }
                retained_witness_hits += report.retained_witness_hits;
                recomputable_skips += report.recomputable_skips;
                loser_kernels_drained += report.loser_kernels_drained;
                loser_kernels_dropped += report.loser_kernels_dropped;
            }
            let elapsed_ns = started.elapsed().as_nanos();
            let queue_after = foil_async_loser_queue_telemetry();
            sample_ns.sort_unstable();
            PolicyBenchRow {
                policy: policy.as_str(),
                iterations,
                target_n,
                workload: workload_name,
                elapsed_ns,
                mean_ns: elapsed_ns as f64 / iterations as f64,
                p50_ns: percentile(&sample_ns, 50),
                p95_ns: percentile(&sample_ns, 95),
                p99_ns: percentile(&sample_ns, 99),
                verified,
                winner,
                cache_hits,
                cache_misses,
                cache_fresh,
                cache_absent_built,
                cache_stale_rebuilt,
                retained_witness_hits,
                recomputable_skips,
                loser_kernels_drained,
                loser_kernels_dropped,
                queue_admitted_tasks: queue_after
                    .admitted_tasks
                    .saturating_sub(queue_before.admitted_tasks),
                queue_dropped_tasks: queue_after
                    .dropped_tasks
                    .saturating_sub(queue_before.dropped_tasks),
                queue_completed_tasks: queue_after
                    .completed_tasks
                    .saturating_sub(queue_before.completed_tasks),
                queue_pending_before: queue_before.pending_tasks,
                queue_pending_after: queue_after.pending_tasks,
                queue_drained_before: !drain_queue_between_policies
                    || drained_before.pending_tasks == 0,
                queue_worker_count: queue_after.worker_count,
            }
        })
        .collect::<Vec<_>>();

    println!("{}", serde_json::to_string_pretty(&rows).unwrap());
}

fn arg_u32(name: &str) -> Option<u32> {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next().and_then(|value| value.parse().ok());
        }
        if let Some(value) = arg.strip_prefix(&format!("{name}=")) {
            return value.parse().ok();
        }
    }
    None
}

fn arg_u64(name: &str) -> Option<u64> {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next().and_then(|value| value.parse().ok());
        }
        if let Some(value) = arg.strip_prefix(&format!("{name}=")) {
            return value.parse().ok();
        }
    }
    None
}

fn arg_string(name: &str) -> Option<String> {
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        if arg == name {
            return args.next();
        }
        if let Some(value) = arg.strip_prefix(&format!("{name}=")) {
            return Some(value.to_owned());
        }
    }
    None
}

fn arg_bool(name: &str) -> bool {
    std::env::args().skip(1).any(|arg| arg == name)
}

fn fail_with_usage(message: &str) -> ! {
    eprintln!("{message}");
    eprintln!(
        "usage: bench-foil-loser-policy [--iterations N] [--n N] [--repetitions N] \
         [--workload fixed|long-tail|saturation] \
         [--policy all|adaptive|cancel|drain|drain-and-cache|integration[,..]] \
         [--drain-queue-between-policies] [--drain-timeout-ms N]"
    );
    std::process::exit(2);
}

fn selected_policies(policy: Option<&str>) -> Result<Vec<RaceLoserPolicy>, String> {
    match policy {
        None | Some("all") => Ok(vec![
            RaceLoserPolicy::Adaptive,
            RaceLoserPolicy::Cancel,
            RaceLoserPolicy::Drain,
            RaceLoserPolicy::DrainAndCache,
            RaceLoserPolicy::Integration,
        ]),
        Some(raw) => raw
            .split(',')
            .map(|policy| {
                let trimmed = policy.trim();
                parse_policy(trimmed).ok_or_else(|| trimmed.to_owned())
            })
            .collect::<Result<Vec<_>, _>>()
            .and_then(|policies| {
                if policies.is_empty() {
                    Err(raw.to_owned())
                } else {
                    Ok(policies)
                }
            }),
    }
}

fn parse_policy(policy: &str) -> Option<RaceLoserPolicy> {
    match policy {
        "adaptive" | "auto" => Some(RaceLoserPolicy::Adaptive),
        "cancel" | "cancel-losers" => Some(RaceLoserPolicy::Cancel),
        "drain" => Some(RaceLoserPolicy::Drain),
        "drain-and-cache" | "drain_and_cache" | "cache" => Some(RaceLoserPolicy::DrainAndCache),
        "integration"
        | "async-drain-and-cache"
        | "async_drain_and_cache"
        | "async-cache"
        | "async" => Some(RaceLoserPolicy::Integration),
        _ => None,
    }
}

fn normalized_workload(workload: &str) -> Option<&'static str> {
    match workload {
        "fixed" => Some("fixed"),
        "long-tail" | "long_tail" => Some("long-tail"),
        "saturation" | "saturate" | "queue-saturation" | "queue_saturation" => Some("saturation"),
        _ => None,
    }
}

fn workload_n(workload: &str, iteration: u32, base: u32) -> u32 {
    match workload {
        "long-tail" => long_tail_n(iteration, base),
        "saturation" => base,
        _ => base,
    }
}

fn long_tail_n(iteration: u32, base: u32) -> u32 {
    match iteration % 100 {
        0 => base.saturating_add(8),
        1..=4 => base.saturating_add(5),
        5..=19 => base.saturating_add(2),
        _ => base,
    }
}

fn percentile(sorted: &[u128], percentile: usize) -> u128 {
    if sorted.is_empty() {
        return 0;
    }
    let index = ((sorted.len() - 1) * percentile) / 100;
    sorted[index]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn selected_policies_rejects_unknown_policy() {
        assert_eq!(
            selected_policies(Some("integration,wat")).expect_err("unknown policy"),
            "wat"
        );
    }

    #[test]
    fn selected_policies_accepts_comma_separated_aliases() {
        assert_eq!(
            selected_policies(Some("adaptive,async-drain-and-cache")).expect("policies"),
            vec![RaceLoserPolicy::Adaptive, RaceLoserPolicy::Integration]
        );
    }

    #[test]
    fn normalized_workload_rejects_unknown_workload() {
        assert_eq!(normalized_workload("mystery"), None);
    }

    #[test]
    fn normalized_workload_accepts_queue_saturation_alias() {
        assert_eq!(normalized_workload("queue_saturation"), Some("saturation"));
    }
}
